import type locales from './locales'
export type Locale = keyof typeof locales

function unwrapDefault<T>(mod: Promise<{ default: T }>): Promise<T> {
  return mod.then((m) => {
    const d = m.default
    return 'default' in (d as any) ? (d as { default: T }).default : d
  })
}

export const dynamicLocales: Record<Locale, () => Promise<moment.Locale>> = {
  'de-DE': () => unwrapDefault(import('./locales/de-DE.js')),
  'en-US': () => unwrapDefault(import('./locales/en-US.js')),
  'es-ES': () => unwrapDefault(import('./locales/es-ES.js')),
  'fr-FR': () => unwrapDefault(import('./locales/fr-FR.js')),
  'hi-IN': () => unwrapDefault(import('./locales/hi-IN.js')),
  'id-ID': () => unwrapDefault(import('./locales/id-ID.js')),
  'it-IT': () => unwrapDefault(import('./locales/it-IT.js')),
  'ja-JP': () => unwrapDefault(import('./locales/ja-JP.js')),
  'ko-KR': () => unwrapDefault(import('./locales/ko-KR.js')),
  'ms-MY': () => unwrapDefault(import('./locales/ms-MY.js')),
  'pt-BR': () => unwrapDefault(import('./locales/pt-BR.js')),
  'ru-RU': () => unwrapDefault(import('./locales/ru-RU.js')),
  'th-TH': () => unwrapDefault(import('./locales/th-TH.js')),
  'vi-VN': () => unwrapDefault(import('./locales/vi-VN.js')),
  'zh-CN': () => unwrapDefault(import('./locales/zh-CN.js')),
  'zh-HK': () => unwrapDefault(import('./locales/zh-HK.js')),
  'zh-TW': () => unwrapDefault(import('./locales/zh-TW.js')),
}

// 不支持 dynamic import expression，这里统一处理下
// https://github.com/webpack/webpack/issues/13865
export async function getLocale(locale: Locale) {
  return (dynamicLocales[locale] || dynamicLocales['en-US'])()
}
